import React, { useState, useMemo, useCallback } from 'react';
import { useNavigate } from 'react-router-dom';
import { Input, SearchInput, addToast, localInputToISOWithOffset } from '@linm-soft/common-components';
import { useAppDispatch } from '../../../store/hooks';
import { tscdService } from '../../../services/tscd/tscdService';
import { createFixedAssetSearchConfig, createDepartmentIdSearchConfig } from '../../../components/search';
import { useVoucherInitData } from '../../../hooks/useVoucherInitData';
import { DEPARTMENT_FIELD_LABEL, resolveDepartmentById } from '../../../utils/departmentField';
import { getApiErrorMessage } from '../../../utils/getApiErrorMessage';
import { scrollToValidationTarget } from '../../../utils/scrollToValidationTarget';
import { DocumentFormHeader } from '../../../components/layout';
import df from '../../../styles/documentForm.module.css';

const TEST_ID = 'tscd-dieu-chuyen';
const DEPT_INIT_FORM = 'create-advance-payment';

const FIELD_ORDER = ['fixedAssetId', 'transferDate', 'fromDepartmentId', 'toDepartmentId'] as const;
type FieldKey = (typeof FIELD_ORDER)[number];
type FieldErrors = Partial<Record<FieldKey, string>>;

function scrollToFirstError(errors: FieldErrors): void {
  const first = FIELD_ORDER.find(k => errors[k]);
  if (first) scrollToValidationTarget(`${TEST_ID}-field-${first}`);
}

const TscdDieuChuyenPage: React.FC = () => {
  const dispatch = useAppDispatch();
  const navigate = useNavigate();
  const { departmentOptions } = useVoucherInitData(DEPT_INIT_FORM);
  const assetSearchConfig = useMemo(() => createFixedAssetSearchConfig(), []);
  const departmentIdSearchConfig = useMemo(
    () => createDepartmentIdSearchConfig(departmentOptions),
    [departmentOptions],
  );
  const [fixedAssetId, setFixedAssetId] = useState('');
  const [assetCode, setAssetCode] = useState('');
  const [fromDepartmentId, setFromDepartmentId] = useState('');
  const [toDepartmentId, setToDepartmentId] = useState('');
  const [transferDate, setTransferDate] = useState(new Date().toISOString().slice(0, 10));
  const [note, setNote] = useState('');
  const [saving, setSaving] = useState(false);
  const [fieldErrors, setFieldErrors] = useState<FieldErrors>({});

  const patchFieldError = useCallback((key: FieldKey, value?: string) => {
    setFieldErrors(prev => {
      if (!value) {
        if (!(key in prev)) return prev;
        const next = { ...prev };
        delete next[key];
        return next;
      }
      return { ...prev, [key]: value };
    });
  }, []);

  const fromDept = resolveDepartmentById(fromDepartmentId, departmentOptions);
  const toDept = resolveDepartmentById(toDepartmentId, departmentOptions);

  const validate = (): FieldErrors => {
    const errors: FieldErrors = {};
    if (!fixedAssetId) errors.fixedAssetId = 'TSCĐ là bắt buộc';
    if (!transferDate) errors.transferDate = 'Ngày điều chuyển là bắt buộc';
    if (!fromDepartmentId) errors.fromDepartmentId = `${DEPARTMENT_FIELD_LABEL} nguồn là bắt buộc`;
    if (!toDepartmentId) errors.toDepartmentId = `${DEPARTMENT_FIELD_LABEL} đích là bắt buộc`;
    if (fromDepartmentId && toDepartmentId && fromDepartmentId === toDepartmentId) {
      errors.toDepartmentId = 'Đơn vị đích phải khác đơn vị nguồn';
    }
    return errors;
  };

  const handleSave = async () => {
    const errors = validate();
    if (Object.keys(errors).length > 0) {
      setFieldErrors(errors);
      scrollToFirstError(errors);
      dispatch(addToast({ message: 'Vui lòng kiểm tra các trường bắt buộc', type: 'error' }));
      return;
    }
    setSaving(true);
    try {
      await tscdService.createTransfer({
        fixedAssetId,
        transferDate: localInputToISOWithOffset(transferDate),
        fromDepartmentId,
        toDepartmentId,
        note: note.trim() || undefined,
      });
      dispatch(addToast({ message: 'Điều chuyển TSCĐ thành công', type: 'success' }));
      navigate('/tscd/danh-sach');
    } catch (e: unknown) {
      dispatch(addToast({ message: getApiErrorMessage(e, 'Lỗi điều chuyển TSCĐ'), type: 'error' }));
    } finally {
      setSaving(false);
    }
  };

  return (
    <div className={df.page} data-testid={`${TEST_ID}-form`}>
      <DocumentFormHeader
        onBack={() => navigate('/tscd/danh-sach')}
        title="Điều chuyển tài sản"
        isNew
        saving={saving}
        saveLabel="Ghi nhận"
        onSave={handleSave}
      />
      <div className={df.section}>
        <h2 className={df.sectionTitle}>Thông tin điều chuyển</h2>
        <div className={df.row4}>
          <div className={df.spanCol2} id={`${TEST_ID}-field-fixedAssetId`} data-testid={`${TEST_ID}-field-fixedAssetId`}>
            <label className={df.label}>TSCĐ *</label>
            <SearchInput
              config={assetSearchConfig}
              value={fixedAssetId}
              primaryDisplay={assetCode}
              onChange={a => {
                setFixedAssetId(a.id);
                setAssetCode(a.code);
                if (a.departmentId) setFromDepartmentId(a.departmentId);
                patchFieldError('fixedAssetId');
              }}
              onClear={() => {
                setFixedAssetId('');
                setAssetCode('');
                setFromDepartmentId('');
                patchFieldError('fixedAssetId');
              }}
              showLabel={false}
              showSecondaryInput={false}
              error={fieldErrors.fixedAssetId}
            />
          </div>
          <div className={df.field} id={`${TEST_ID}-field-transferDate`} data-testid={`${TEST_ID}-field-transferDate`}>
            <label className={df.label}>Ngày điều chuyển *</label>
            <Input
              type="date"
              value={transferDate}
              onChange={e => {
                setTransferDate(e.target.value);
                patchFieldError('transferDate');
              }}
              error={fieldErrors.transferDate}
              required
            />
          </div>
          <div className={df.field} aria-hidden />
        </div>
        <div className={df.row4}>
          <div className={df.field} id={`${TEST_ID}-field-fromDepartmentId`} data-testid={`${TEST_ID}-field-fromDepartmentId`}>
            <label className={df.label}>{DEPARTMENT_FIELD_LABEL} nguồn *</label>
            <SearchInput
              config={departmentIdSearchConfig}
              value={fromDepartmentId}
              primaryDisplay={fromDept?.code ?? ''}
              secondaryDisplay={fromDept?.name ?? ''}
              onChange={d => {
                setFromDepartmentId(d.id);
                patchFieldError('fromDepartmentId');
                patchFieldError('toDepartmentId');
              }}
              onClear={() => {
                setFromDepartmentId('');
                patchFieldError('fromDepartmentId');
              }}
              showLabel={false}
              showSecondaryInput={false}
              placeholder="Mã hoặc tên đơn vị..."
              error={fieldErrors.fromDepartmentId}
            />
          </div>
          <div className={df.field} id={`${TEST_ID}-field-toDepartmentId`} data-testid={`${TEST_ID}-field-toDepartmentId`}>
            <label className={df.label}>{DEPARTMENT_FIELD_LABEL} đích *</label>
            <SearchInput
              config={departmentIdSearchConfig}
              value={toDepartmentId}
              primaryDisplay={toDept?.code ?? ''}
              secondaryDisplay={toDept?.name ?? ''}
              onChange={d => {
                setToDepartmentId(d.id);
                patchFieldError('toDepartmentId');
              }}
              onClear={() => {
                setToDepartmentId('');
                patchFieldError('toDepartmentId');
              }}
              showLabel={false}
              showSecondaryInput={false}
              placeholder="Mã hoặc tên đơn vị..."
              error={fieldErrors.toDepartmentId}
            />
          </div>
          <div className={`${df.field} ${df.spanCol2}`} data-testid={`${TEST_ID}-field-note`}>
            <label className={df.label}>Ghi chú</label>
            <Input value={note} onChange={e => setNote(e.target.value)} />
          </div>
        </div>
      </div>
    </div>
  );
};

export default TscdDieuChuyenPage;
