const DEFAULT_DELAY_MS = 120;

/** Scroll to validation banner or section after client-side validate fails. */
export function scrollToValidationTarget(
  elementId: string,
  delayMs = DEFAULT_DELAY_MS,
): void {
  if (!elementId) return;
  setTimeout(() => {
    document.getElementById(elementId)?.scrollIntoView({
      behavior: 'smooth',
      block: 'start',
    });
  }, delayMs);
}
